import{_ as a,a as e,b as d,c as s}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as l,o as i,c as o,a2 as n}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Добавление канала S3","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/upload/s3.md","filePath":"ru-RU/upload/s3.md","lastUpdated":1781962217000}'),c={name:"ru-RU/upload/s3.md"};function r(p,t,h,u,b,m){return i(),o("div",null,[...t[0]||(t[0]=[n(`<h1 id="добавление-канала-s3" tabindex="-1">Добавление канала S3 <a class="header-anchor" href="#добавление-канала-s3" aria-label="Permalink to &quot;Добавление канала S3&quot;">​</a></h1><h2 id="когда-это-лучшии-вариант" tabindex="-1">Когда это лучший вариант <a class="header-anchor" href="#когда-это-лучшии-вариант" aria-label="Permalink to &quot;Когда это лучший вариант&quot;">​</a></h2><p>Используйте канал S3, если:</p><ul><li>хотите подключить любое S3-совместимое объектное хранилище, например Cloudflare R2, Backblaze B2, MinIO, AWS S3 или другого совместимого провайдера;</li><li>вам удобна стандартная модель настройки S3: <code>Endpoint</code>, Access Key и Secret Key;</li><li>не хотите использовать нативный Cloudflare R2 binding или ваш провайдер хранилища не является Cloudflare R2.</li></ul><h2 id="что-подготовить-заранее" tabindex="-1">Что подготовить заранее <a class="header-anchor" href="#что-подготовить-заранее" aria-label="Permalink to &quot;Что подготовить заранее&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Что нужно</th><th>Зачем это нужно</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>API endpoint S3 для объектного хранилища.</td></tr><tr><td>Имя bucket</td><td>Bucket, где будут храниться файлы.</td></tr><tr><td>Region</td><td>Регион хранилища. Для Cloudflare R2 обычно <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>Идентификатор ключа доступа S3.</td></tr><tr><td>Secret Access Key</td><td>Секретный ключ доступа S3.</td></tr><tr><td>CDN domain</td><td>Необязательный собственный домен для доступа к файлам.</td></tr></tbody></table><p>Пример для Cloudflare R2 через S3 API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="где-добавить-канал" tabindex="-1">Где добавить канал <a class="header-anchor" href="#где-добавить-канал" aria-label="Permalink to &quot;Где добавить канал&quot;">​</a></h2><ol><li>Откройте системные настройки.</li><li>Перейдите в настройки загрузки.</li><li>Нажмите Add Channel в правом верхнем углу.</li><li>Выберите <code>S3</code>.</li></ol><h2 id="поля-настроики" tabindex="-1">Поля настройки <a class="header-anchor" href="#поля-настроики" aria-label="Permalink to &quot;Поля настройки&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Поле</th><th>Что означает</th><th>Обязательно</th></tr></thead><tbody><tr><td>Название канала</td><td>Понятное имя S3-канала, например <code>s3test</code> или <code>R2-S3</code>.</td><td>Да</td></tr><tr><td>Enable channel</td><td>Определяет, участвует ли канал в выборе хранилища для загрузки.</td><td>Рекомендуется</td></tr><tr><td>Endpoint</td><td>Полный endpoint S3-сервиса, включая <code>https://</code>.</td><td>Да</td></tr><tr><td>Custom CDN domain</td><td>Необязательно. Если задан, сгенерированные ссылки на файлы будут использовать этот домен.</td><td>Нет</td></tr><tr><td>Bucket name</td><td>Имя bucket, например <code>s3test</code> или <code>img-r2</code>.</td><td>Да</td></tr><tr><td>Bucket region</td><td>Регион. Для Cloudflare R2 обычно <code>auto</code>.</td><td>Да</td></tr><tr><td>Access Key ID</td><td>Идентификатор ключа доступа S3.</td><td>Да</td></tr><tr><td>Secret Access Key</td><td>Секретный ключ доступа S3.</td><td>Да</td></tr><tr><td>Path-style access</td><td>Переключатель совместимости. По умолчанию выключен. Некоторым MinIO, OpenList или self-hosted S3-сервисам он может понадобиться.</td><td>Нет</td></tr><tr><td>Quota limit</td><td>Определяет, учитывается ли емкость канала при выборе хранилища.</td><td>Нет</td></tr><tr><td>Capacity limit</td><td>Требуется после включения quota limit, например <code>10 GB</code>.</td><td>Да, если включен quota limit</td></tr><tr><td>Threshold</td><td>Останавливает запись после достижения этого процента использования, например <code>90%</code>.</td><td>Да, если включен quota limit</td></tr><tr><td>Remark</td><td>Заметки для вашего обслуживания.</td><td>Нет</td></tr></tbody></table><h2 id="создание-s3-api-keys-для-cloudflare-r2" tabindex="-1">Создание S3 API keys для Cloudflare R2 <a class="header-anchor" href="#создание-s3-api-keys-для-cloudflare-r2" aria-label="Permalink to &quot;Создание S3 API keys для Cloudflare R2&quot;">​</a></h2><ol><li>Откройте Cloudflare Dashboard.</li><li>Перейдите в <code>R2 Object Storage</code>.</li><li>Найдите <code>Manage R2 API Tokens</code> или пункт управления API-токенами.</li></ol><p>![Вход к R2 API token](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>Создайте R2 API token с доступом к нужному bucket.</li></ol><p><img src="`+a+'" alt="Создание account API token" loading="lazy"></p><ol start="5"><li>Скопируйте созданные <code>Access Key ID</code> и <code>Secret Access Key</code>.</li></ol><p><img src="'+e+'" alt="Копирование значений токена" loading="lazy"></p><ol start="6"><li>Вернитесь на страницу R2 bucket и проверьте имя bucket.</li><li>Запишите S3 API endpoint для аккаунта. Обычно он выглядит так:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="настроика" tabindex="-1">Настройка <a class="header-anchor" href="#настроика" aria-label="Permalink to &quot;Настройка&quot;">​</a></h2><ol><li>Откройте настройки загрузки.</li><li>Нажмите Add Channel.</li><li>Выберите <code>S3</code>.</li><li>Введите понятное имя канала, например <code>s3test</code>.</li><li>В поле <code>Endpoint</code> введите S3 API endpoint.</li><li>Если используете собственный CDN, введите его в <code>Custom CDN domain</code>; если нет, оставьте поле пустым.</li><li>Введите имя bucket.</li><li>Введите region. Для примера с Cloudflare R2 используйте <code>auto</code>.</li><li>Введите Access Key ID и Secret Access Key.</li><li>Оставьте path-style access выключенным, если провайдер явно не требует другого.</li><li>Если нужен контроль емкости, включите quota limit и введите capacity limit и threshold.</li><li>Нажмите Save.</li></ol><p><img src="'+d+'" alt="Добавление S3 конфигурации" loading="lazy"></p><h2 id="как-проверить" tabindex="-1">Как проверить <a class="header-anchor" href="#как-проверить" aria-label="Permalink to &quot;Как проверить&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Проверка</th><th>Как проверить</th></tr></thead><tbody><tr><td>Карточка канала появилась</td><td>После сохранения на странице настроек загрузки должна появиться карточка S3-канала.</td></tr><tr><td>Канал включен</td><td>Переключатель в правом верхнем углу карточки должен оставаться включенным.</td></tr><tr><td>Основные поля сохранены</td><td>В деталях должны отображаться Endpoint, Bucket, Region, path-style access и связанные поля.</td></tr><tr><td>Загрузка работает</td><td>Загрузите тестовое изображение и убедитесь, что объект появился в целевом bucket.</td></tr><tr><td>Ссылка открывается</td><td>Ссылка на изображение, возвращенная после загрузки, должна открываться нормально.</td></tr><tr><td>Отображение емкости работает</td><td>Если включен quota limit, карточка должна показывать использованную емкость и настроенный лимит.</td></tr></tbody></table><p>Статистика емкости S3 считается по локальным записям файлов в ImgBed, а не через запрос к bucket провайдера в реальном времени. После сохранения S3-конфигурации система пересчитывает учет квоты по текущим записям D1.</p><p><img src="'+s+`" alt="Успешный запрос квоты" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="нужно-ли-включать-path-style-access" tabindex="-1">Нужно ли включать path-style access? <a class="header-anchor" href="#нужно-ли-включать-path-style-access" aria-label="Permalink to &quot;Нужно ли включать path-style access?&quot;">​</a></h3><p>Обычно нет.</p><p>Включайте его только тогда, когда ваш S3-совместимый провайдер не поддерживает virtual-hosted-style URL или документация провайдера прямо требует path-style access. Это может понадобиться для некоторых MinIO, self-hosted S3 и OpenList-совместимых endpoint.</p><h3 id="для-чего-нужен-cdn-domain" tabindex="-1">Для чего нужен CDN domain? <a class="header-anchor" href="#для-чего-нужен-cdn-domain" aria-label="Permalink to &quot;Для чего нужен CDN domain?&quot;">​</a></h3><p>Если перед bucket стоит CDN или собственный домен доступа, укажите его здесь.</p><p>После настройки сгенерированные ссылки на файлы будут использовать этот домен. Если CDN не используется, оставьте поле пустым.</p><h3 id="почему-загрузка-не-проходит" tabindex="-1">Почему загрузка не проходит? <a class="header-anchor" href="#почему-загрузка-не-проходит" aria-label="Permalink to &quot;Почему загрузка не проходит?&quot;">​</a></h3><p>Сначала проверьте:</p><ol><li>Endpoint содержит полный URL с <code>https://</code>.</li><li>Имя bucket правильное.</li><li>Region соответствует требованиям провайдера.</li><li>Access Key ID и Secret Access Key скопированы полностью.</li><li>Ключ имеет право записи в целевой bucket.</li><li>Провайдер не требует path-style access, либо этот режим включен, если нужен.</li></ol><h2 id="короткии-чек-лист" tabindex="-1">Короткий чек-лист <a class="header-anchor" href="#короткии-чек-лист" aria-label="Permalink to &quot;Короткий чек-лист&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Подготовить S3 Endpoint, Bucket, Region, Access Key и Secret Key</span></span>
<span class="line"><span>-&gt; Открыть настройки загрузки</span></span>
<span class="line"><span>-&gt; Добавить канал</span></span>
<span class="line"><span>-&gt; Выбрать S3</span></span>
<span class="line"><span>-&gt; Ввести Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; При необходимости ввести CDN domain</span></span>
<span class="line"><span>-&gt; По умолчанию оставить path-style access выключенным</span></span>
<span class="line"><span>-&gt; При необходимости включить quota limit</span></span>
<span class="line"><span>-&gt; Сохранить</span></span>
<span class="line"><span>-&gt; Загрузить тестовое изображение и проверить результат</span></span></code></pre></div>`,40)])])}const S=l(c,[["render",r]]);export{g as __pageData,S as default};
